import{_ as t}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{o as i,c as s,e as a}from"./chunks/vendor-mermaid.BXjKBAcr.js";const u=JSON.parse('{"title":"New Fiscal Policy 2083/84","description":"Understanding the impact of the latest budget on small and medium enterprises.","frontmatter":{"title":"New Fiscal Policy 2083/84","description":"Understanding the impact of the latest budget on small and medium enterprises.","date":"2026-02-10T00:00:00.000Z","author":"CA Santosh Pandey","twitter":"https://twitter.com/artha","head":[["meta",{"name":"keywords","content":"fiscal policy, nepal budget, sme tax"}],["meta",{"property":"og:image","content":"https://arthaadvisory.com.np/og_image_test.jpg"}],["meta",{"property":"og:title","content":"New Fiscal Policy 2083/84 | Artha Advisory"}],["meta",{"property":"og:description","content":"Understanding the impact of the latest budget on small and medium enterprises."}],["meta",{"name":"description","content":"Understanding the impact of the latest budget on small and medium enterprises."}]]},"headers":[],"relativePath":"resources/insights/fiscal-policy.md","filePath":"resources/insights/fiscal-policy.md"}'),n={name:"resources/insights/fiscal-policy.md"};function o(r,e,l,c,d,p){return i(),s("div",null,[...e[0]||(e[0]=[a('<p>The new fiscal policy introduces several changes aimed at boosting the SME sector while expanding the tax base and simplifying compliance obligations.</p><h2 id="key-highlights" tabindex="-1">Key Highlights <a class="header-anchor" href="#key-highlights" aria-label="Permalink to &quot;Key Highlights&quot;">​</a></h2><ul><li><strong>Tax holidays for startups</strong> — Industries registered in underdeveloped districts may qualify for up to 10 years of income tax exemption under the latest Industrial Enterprises Act amendments.</li><li><strong>Reduced import duties on raw materials</strong> — Manufacturing-oriented importers can benefit from reduced customs duty on select inputs, particularly in agro-processing and IT hardware.</li><li><strong>New VAT compliance requirements</strong> — The IRD has introduced mandatory e-billing for businesses with turnover exceeding NPR 50 Lakh, effective from Shrawan 2083.</li><li><strong>Social Security Fund (SSF) expansion</strong> — Employer contribution rates remain at 20%, but the penalty structure for late deposits has been tightened.</li></ul><h2 id="what-this-means-for-your-business" tabindex="-1">What This Means for Your Business <a class="header-anchor" href="#what-this-means-for-your-business" aria-label="Permalink to &quot;What This Means for Your Business&quot;">​</a></h2><p>The policy shifts the government&#39;s strategy toward incentivizing formal registration and digital compliance. Businesses that proactively adopt e-billing and formalize their employment contracts will be best positioned to access the new incentive structure.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>Need a tax impact assessment for your business?</strong> Our team can model how the new fiscal policy affects your effective tax rate and compliance obligations.</p></div><p><a href="/contact"><strong>Get a Fiscal Policy Briefing →</strong></a></p>',7)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
